    print("\n\n=== Testing QNG Optimizer Usage ===")

    try:
        dev = qml.device('default.qubit', wires=2)

        @qml.qnode(dev)
        def circuit_rot(params):
            qml.Rot(params[0], params[1], params[2], wires=0)
            return qml.expval(qml.PauliZ(0))

        params = np.array([0.1, 0.2, 0.3])
        print("Created circuit with Rot gate")

        # Try to compute metric tensor (this uses generators)
        print("Attempting to compute metric tensor...")
        metric_tensor = qml.metric_tensor(circuit_rot)(params)
        print(f"Metric tensor computed successfully: {metric_tensor}")

    except Exception as e:
        print(f"Error with Rot in QNG context: {e}")
        import traceback
        traceback.print_exc()

    try:
        dev = qml.device('default.qubit', wires=2)

        @qml.qnode(dev)
        def circuit_crot(params):
            qml.CRot(params[0], params[1], params[2], wires=[0, 1])
            return qml.expval(qml.PauliZ(0))

        params = np.array([0.1, 0.2, 0.3])
        print("Created circuit with CRot gate")

        # Try to compute metric tensor (this uses generators)
        print("Attempting to compute metric tensor...")
        metric_tensor = qml.metric_tensor(circuit_crot)(params)
        print(f"Metric tensor computed successfully: {metric_tensor}")

    except Exception as e:
        print(f"Error with CRot in QNG context: {e}")
        import traceback
        traceback.print_exc()

