#!/usr/bin/env python3

"""
Test that verifies Rot gate now HAS a generator (opposite of the old failing test).
"""

import pytest
import pennylane as qml
from pennylane.qnodes.qubit import QubitQNode
from pennylane.qnodes.base import QuantumFunctionError

def test_rot_now_has_generator():
    """Test that Rot gate now has a defined generator and works with metric tensor."""
    dev = qml.device("default.qubit", wires=1)

    def circuit(a):
        qml.Rot(a, 0, 0, wires=0)
        return qml.expval(qml.PauliX(0))

    circuit = QubitQNode(circuit, dev)

    # This should NOT raise an exception anymore
    # Previously it would raise: QuantumFunctionError "has no defined generator"
    try:
        metric_tensor = circuit.metric_tensor([1], only_construct=False)
        print(f"SUCCESS: Metric tensor computed: {metric_tensor}")
        assert True  # Test passes if no exception is raised
    except QuantumFunctionError as e:
        if "has no defined generator" in str(e):
            pytest.fail("Rot gate should now have a generator, but it still doesn't")
        else:
            raise  # Re-raise if it's a different error
    except Exception:
        # Other exceptions might occur, but not the "no generator" one
        raise

def test_crot_now_has_generator():
    """Test that CRot gate now has a defined generator and works with metric tensor."""
    dev = qml.device("default.qubit", wires=2)

    def circuit(a):
        qml.CRot(a, 0, 0, wires=[0, 1])
        return qml.expval(qml.PauliX(0))

    circuit = QubitQNode(circuit, dev)

    # This should NOT raise an exception anymore
    try:
        metric_tensor = circuit.metric_tensor([1], only_construct=False)
        print(f"SUCCESS: CRot metric tensor computed: {metric_tensor}")
        assert True  # Test passes if no exception is raised
    except QuantumFunctionError as e:
        if "has no defined generator" in str(e):
            pytest.fail("CRot gate should now have a generator, but it still doesn't")
        else:
            raise  # Re-raise if it's a different error
    except Exception:
        # Other exceptions might occur, but not the "no generator" one
        raise

if __name__ == "__main__":
    test_rot_now_has_generator()
    test_crot_now_has_generator()
    print("✅ All tests passed! Rot and CRot now have generators.")
